    /// Initialize all Java bindings in this module.
    ///
    /// This loads and caches JClass references and method/field IDs for all
    /// bindings in this module and its child modules.
    ///
    /// # Arguments
    ///
    /// * `env` - The JNI environment
    /// * `loader` - The LoaderContext to use for loading classes
    pub fn jni_init(env: &::jni::Env, loader: &::jni::refs::LoaderContext) -> ::jni::errors::Result<()> {
        let _ = DafAPI::get(env, loader)?;
        let _ = HebrewDateFormatterAPI::get(env, loader)?;
        let _ = JewishCalendarAPI::get(env, loader)?;
        let _ = JewishCalendarParshaAPI::get(env, loader)?;
        let _ = JewishDateAPI::get(env, loader)?;
        let _ = TefilaRulesAPI::get(env, loader)?;
        let _ = YerushalmiYomiCalculatorAPI::get(env, loader)?;
        let _ = YomiCalculatorAPI::get(env, loader)?;
        Ok(())
    }
